prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?model) AS ?modelCount)
  (MIN(?created) AS ?minCreated)
  (MAX(?created) AS ?maxCreated)
  (SAMPLE(?datasetName) AS ?corpusDataset)
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "c41660388a04449a995dccf97d894f46" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         tai:modelCreated ?created ;
         tai:corpusId ?corpusId .
  OPTIONAL {
    ?corpus a bboExt:Corpus ;
            tai:corpusId ?corpusId ;
            tai:sourceDataset ?datasetName .
  }
}
GROUP BY ?corpusDataset

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?org ?orgName ?orgLabel ?orgId WHERE {
  {
    ?org a bboExt:Organization ;
         tai:organizationId ?orgId .
    FILTER(CONTAINS(LCASE(STR(?orgId)), LCASE("c41660388a04449a995dccf97d894f46")))
  }
  UNION
  {
    ?org a bboExt:Organization ;
         bbo:name ?orgName .
    FILTER(CONTAINS(LCASE(STR(?orgName)), LCASE("c41660388a04449a995dccf97d894f46")))
  }
  UNION
  {
    ?org a bboExt:Organization ;
         rdfs:label ?orgLabel .
    FILTER(CONTAINS(LCASE(STR(?orgLabel)), LCASE("c41660388a04449a995dccf97d894f46")))
  }
  OPTIONAL { ?org bbo:name ?orgName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?model) AS ?modelCount)
  (MIN(?created) AS ?minCreated)
  (MAX(?created) AS ?maxCreated)
  (COUNT(DISTINCT ?choreo) AS ?choreographyCount)
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?participant) AS ?participantCount)
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId ?orgId .
  FILTER(CONTAINS(LCASE(STR(?orgId)), LCASE("c41660388a04449a995dccf97d894f46")))

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         tai:modelCreated ?created .

  ?def tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?def .

  OPTIONAL {
    ?task a bboExt:ChoreographyTask ;
          tai:belongsTo ?choreo .
  }
  OPTIONAL {
    ?participant a bboExt:Participant ;
                 tai:belongsTo ?choreo .
  }
}
GROUP BY ?org
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (AVG(?taskPerChoreo) AS ?avgTasksPerChoreo)
  (AVG(?participantsPerChoreo) AS ?avgParticipantsPerChoreo)
  (AVG(?choreoNodesEstimate) AS ?avgNodeEstimate)
  (COUNT(DISTINCT ?partName) AS ?distinctParticipantNames)
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId ?orgId .
  FILTER(CONTAINS(LCASE(STR(?orgId)), LCASE("c41660388a04449a995dccf97d894f46")))

  ?model a bboExt:Model ;
         tai:belongsTo ?org .

  ?def tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?def .

  {
    SELECT ?choreo (COUNT(DISTINCT ?task) AS ?taskPerChoreo) (COUNT(DISTINCT ?participant) AS ?participantsPerChoreo) (COUNT(DISTINCT ?anyNode) AS ?choreoNodesEstimate) WHERE {
      ?task a bboExt:ChoreographyTask ;
            tai:belongsTo ?choreo .
      ?participant a bboExt:Participant ;
                   tai:belongsTo ?choreo .
      OPTIONAL { ?anyNode tai:belongsTo ?choreo . }
    }
    GROUP BY ?choreo
  }
}
GROUP BY ?org
